import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, Layers } from 'lucide-react';
import { Link } from 'react-router-dom';

export const AdminSeries = () => {
  const [series, setSeries] = useState<any[]>([]);
  useEffect(() => { AdminService.getAllSeries().then(res => setSeries(res.data)); }, []);

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-end">
        <h1 className="text-4xl font-black uppercase italic">Artwork <span className="text-primary">Series</span></h1>
        <Link to="/admin/series/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2">
          <Plus size={16} /> New Series
        </Link>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {series.map((s: any) => (
          <div key={s._id} className="bg-white p-8 rounded-[2.5rem] border border-gray-100 flex items-center justify-between group shadow-sm">
            <div className="flex items-center gap-4">
              <Layers className="text-primary" size={24} />
              <h4 className="font-black uppercase text-xs italic">{s.Title_En}</h4>
            </div>
            <button className="p-3 bg-red-50 text-red-500 rounded-xl"><Trash2 size={16}/></button>
          </div>
        ))}
      </div>
    </div>
  );
};
